                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">Xoay vòng tự động để tránh giới hạn</p>
                </div>
                <button onClick={() => setShowKeyModal(false)} className="p-2 text-slate-300 hover:text-slate-500 transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>
              <div className="space-y-4">
                <div className="bg-orange-50 border border-orange-100 p-4 rounded-2xl flex gap-3">
                  <svg className="w-5 h-5 text-orange-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  <p className="text-[11px] text-orange-700 leading-relaxed font-medium">Nhập mỗi API Key trên 1 dòng. Hệ thống sẽ sử dụng tuần tự các Key này cho mỗi lượt tạo ảnh để tối ưu tốc độ và quota.</p>
                </div>
                <textarea value={tempKeys} onChange={(e) => setTempKeys(e.target.value)} placeholder="Paste danh sách API Key tại đây..." className="w-full h-64 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-mono focus:ring-4 focus:ring-orange-50 outline-none resize-none" />
                <div className="flex gap-3">
                  <button onClick={() => setShowKeyModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">HỦY BỔ</button>
                  <button onClick={saveKeys} className="flex-1 py-4 bg-orange-600 text-white font-black rounded-2xl text-xs uppercase tracking-widest shadow-lg shadow-orange-100 hover:bg-orange-700 active:scale-95 transition-all">LƯU DANH SÁCH</button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </ErrorBoundary>
  );
};

