import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Task 1: Tạo kịch bản chia giai đoạn dựa trên ý tưởng
 */
export const generateTimelapseScript = async (
  idea: string,
  frameCount: number
): Promise<string[]> => {
  const ai = getAiClient();
  const prompt = `
    Nhiệm vụ: Tạo kịch bản cho video Timelapse dài ${frameCount * 8} giây, gồm ${frameCount} giai đoạn biến đổi.
    Ý tưởng gốc của người dùng: "${idea}"

    YÊU CẦU:
    1. Giai đoạn 1 BẮT BUỘC là "Hiện trạng ban đầu" (Khớp với hình ảnh người dùng tải lên).
    2. Các giai đoạn tiếp theo mô tả sự thay đổi CỘNG DỒN, từng bước một.
    3. Mỗi mô tả giai đoạn phải ngắn gọn, tập trung vào các chi tiết hình ảnh sẽ được thêm vào.
    4. Trả về mảng JSON đúng ${frameCount} phần tử chuỗi.

    Ví dụ: ["Khu đất trống ban đầu", "Rải sỏi và làm sạch bề mặt", "Lắp đặt bàn ghế gỗ và mái che", ...]
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Timelapse script failed", e);
    return Array(frameCount).fill("Đang chờ kịch bản...");
  }
};

/**
 * Task 2: Tạo ảnh biến đổi cộng dồn (Image-to-Image)
 */
export const generateTimelapseImage = async (
  previousImageBase64: string,
  currentContent: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    TASK: Generate a high-quality 9:16 vertical image for a timelapse sequence.
    REFERENCE: Use the provided image as the EXACT base.

    ACTION: Maintain 100% of the original composition, structures, and static elements from the reference. 
    ADD the following details based on this transformation stage: "${currentContent}".

    REQUIREMENTS:
    1. The transformation must look natural and additive (like a real timelapse).
    2. Keep the camera angle and lighting consistent with the reference.
    3. The added objects must blend perfectly into the environment.
    4. NO TEXT, NO WATERMARKS, NO UI.

    ${regenNote ? `USER REGEN NOTE: ${regenNote}` : ""}
    STYLE: Realistic Photorealistic, 8k resolution.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { 
        parts: [
          { inlineData: { mimeType: 'image/png', data: previousImageBase64.split(',')[1] } },
          { text: prompt }
        ] 
      },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    console.error("Timelapse image failed", e);
    throw e;
  }
};

/**
 * Task 3: Tạo Prompt Video cho mỗi cảnh
 */
export const generateTimelapseVideoPrompt = async (
  content: string,
  imageBase64: string
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Nhiệm vụ: Viết prompt chi tiết bằng TIẾNG VIỆT để tạo video AI (VEO-3) cho cảnh timelapse sau: "${content}".
    Dựa trên hình ảnh tham chiếu, hãy mô tả chuyển động sống động của con người hoặc sự thay đổi của môi trường.

    CẤU TRÚC PROMPT (VIẾT LIỀM MẠCH TRÊN 1 DÒNG):
    Mô tả chi tiết nhân vật (nếu có) đang thực hiện hành động "${content}", bối cảnh xung quanh giữ nguyên như ảnh, ánh sáng tự nhiên, chuyển động máy ảnh pan hoặc zoom nhẹ, 4k, realistic.

    YÊU CẦU: Chỉ trả về 1 dòng duy nhất bằng tiếng Việt.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { 
        parts: [
          { inlineData: { mimeType: 'image/png', data: imageBase64.split(',')[1] } },
          { text: prompt }
        ] 
      }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (e) {
    return "Error generating prompt.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { label: '2 cảnh - 16s', count: 2 },
  { label: '3 cảnh - 24s', count: 3 },
  { label: '4 cảnh - 32s', count: 4 },
  { label: '5 cảnh - 40s', count: 5 },
  { label: '6 cảnh - 48s', count: 6 },
  { label: '7 cảnh - 56s', count: 7 },
  { label: '8 cảnh - 64s', count: 8 },
];

const TimelapseModule: React.FC = () => {
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [idea, setIdea] = useState('');
  const [frameCount, setFrameCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setBaseFile(file);
      setBasePreview(URL.createObjectURL(file));
    }
  };

  const handleStart = async () => {
    if (!basePreview || !idea.trim()) {
      alert("Vui lòng tải ảnh và nhập ý tưởng biến đổi.");
      return;
    }
    setIsProcessing(true);
    try {
      const script = await service.generateTimelapseScript(idea, frameCount);
      const newSegments: TimelapseSegment[] = script.map((content, i) => ({
        id: i + 1,
        content: content,
        image: { 
          url: i === 0 ? basePreview : '', 
          loading: false,
          regenNote: '' 
        },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setSegments(newSegments);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const currentIndex = id - 1;
    const previousIndex = currentIndex - 1;
    if (currentIndex <= 0 || !segments[previousIndex].image.url) {
      alert("Cảnh 1 dùng ảnh gốc, hoặc cảnh trước đó chưa có ảnh.");
      return;
    }

    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));
    try {
      const currentSeg = segments[currentIndex];
      const previousUrl = segments[previousIndex].image.url;
      const url = await service.generateTimelapseImage(previousUrl, currentSeg.content, currentSeg.image.regenNote);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false } } : s));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const currentSeg = segments.find(s => s.id === id);
    if (!currentSeg || !currentSeg.image.url) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateTimelapseVideoPrompt(currentSeg.content, currentSeg.image.url);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("ZIP library not loaded");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        if (base64) {
          zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
          count++;
        }
      }
    });
    if (count === 0) return alert("Không có ảnh để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadAllPrompts = () => {
    const text = segments.map(s => s.videoPrompt.text).filter(t => t).join('\n');
    if (!text) return alert("Chưa có prompt nào.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `timelapse_prompts_${Date.now()}.txt`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-400 uppercase mb-2 tracking-widest">1. Ảnh gốc ban đầu (Base Image)</label>
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="aspect-video bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center cursor-pointer hover:bg-slate-100 hover:border-orange-400 transition-all overflow-hidden relative group"
              >
                {basePreview ? (
                  <img src={basePreview} className="w-full h-full object-cover" alt="base" />
                ) : (
                  <div className="text-center opacity-30">
                    <svg className="w-12 h-12 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <span className="text-[10px] font-bold uppercase">Tải ảnh nền móng</span>
                  </div>
                )}
                <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
              </div>
            </div>

            <div>
              <label className="block text-[11px] font-black text-slate-400 uppercase mb-2 tracking-widest">2. Thời lượng video dự kiến</label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {DURATION_OPTIONS.map(opt => (
                  <button 
                    key={opt.count}
                    onClick={() => setFrameCount(opt.count)}
                    className={`p-3 rounded-xl text-[10px] font-black transition-all border-2 ${frameCount === opt.count ? 'border-orange-500 bg-orange-50 text-orange-600' : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-slate-200'}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-400 uppercase mb-2 tracking-widest">3. Ý tưởng biến đổi (Timeline Idea)</label>
              <textarea 
                value={idea}
                onChange={e => setIdea(e.target.value)}
                placeholder="VD: Cải tạo khu đất trống thành sân vườn cafe, đầu tiên là dọn dẹp, sau đó rải sỏi, lắp bàn ghế..."
                className="w-full h-48 p-5 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-orange-50 focus:border-orange-500 outline-none transition-all font-medium text-sm leading-relaxed resize-none"
              />
            </div>

            <button 
              onClick={handleStart}
              disabled={isProcessing || !basePreview || !idea.trim()}
              className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all flex items-center justify-center gap-3 uppercase tracking-widest disabled:opacity-50"
            >
              {isProcessing ? "Đang xử lý kịch bản..." : "Bắt đầu tạo Timelapse"}
            </button>
          </div>
        </div>
      </div>

      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl flex flex-col md:flex-row items-center justify-between gap-6">
            <div>
              <h3 className="text-white font-black text-xl uppercase tracking-tighter">Timeline Hành Trình Biến Đổi</h3>
              <p className="text-[10px] text-orange-500 font-bold uppercase tracking-[0.2em] mt-1">Sử dụng tham chiếu ảnh cộng dồn 9:16</p>
