                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase px-1">Nội dung thay đổi:</label>
                    <textarea 
                      value={seg.content}
                      onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))}
                      className="w-full h-24 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white transition-all resize-none leading-relaxed"
                    />
                  </div>

                  {seg.id > 1 && (
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase px-1">Ghi chú sửa ảnh:</label>
                      <input 
                        type="text"
                        value={seg.image.regenNote}
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, image: { ...s.image, regenNote: e.target.value } } : s))}
                        placeholder="VD: sỏi sáng hơn, thêm cây xanh..."
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-[10px] font-bold outline-none focus:bg-white"
                      />
                    </div>
                  )}

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                    {seg.id === 1 ? (
                      <div className="col-span-2 py-3 text-center text-[10px] font-black text-slate-300 uppercase bg-slate-50 rounded-xl border border-dashed">Ảnh gốc tham chiếu</div>
                    ) : (
                      <button 
                        onClick={() => handleGenImage(seg.id)}
                        disabled={seg.image.loading}
                        className="py-3 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase tracking-tighter hover:bg-black transition-all flex items-center justify-center gap-2"
                      >
                        {seg.image.url ? "Tạo lại ảnh" : "Tạo ảnh biến đổi"}
                      </button>
                    )}

                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={!seg.image.url || seg.videoPrompt.loading}
                      className={`py-3 ${seg.id === 1 ? 'col-span-2' : ''} bg-orange-50 text-orange-700 text-[10px] font-black rounded-xl uppercase tracking-tighter border border-orange-100 hover:bg-orange-100 transition-all flex items-center justify-center gap-2`}
                    >
                      Prompt Video
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-4 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-[8px] font-black text-orange-500 uppercase">Kịch bản VEO-3</span>
                      <button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[8px] text-white underline font-black">COPY</button>
                    </div>
                    {seg.videoPrompt.loading ? (
                      <div className="h-10 flex items-center justify-center"><div className="w-4 h-4 border-2 border-orange-500 border-t-white rounded-full animate-spin"></div></div>
                    ) : (
                      <textarea 
                        value={seg.videoPrompt.text}
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, videoPrompt: { ...s.videoPrompt, text: e.target.value } } : s))}
                        className="w-full bg-transparent text-[10px] text-slate-400 italic leading-snug outline-none resize-none h-16 scrollbar-hide"
                      />
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

