              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                Xuất file JSON
              </button>
            </div>
          </div>
        </div>

        <main className="flex-1 pb-32">
          {renderActiveModule()}
        </main>

        <footer className="bg-white border-t border-slate-200 py-4 fixed bottom-0 left-0 right-0 z-[60]">
          <div className="max-w-7xl mx-auto px-6 flex items-center justify-center">
            <div className="text-[#64748b] font-bold text-[12px] tracking-tight uppercase">@COPYRIGHT KÔNG VĂN - 0923.200.820</div>
          </div>
        </footer>

        {/* Import Progress Overlay */}
        {isImporting && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/80 backdrop-blur-md">
            <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl max-w-sm w-full text-center border border-slate-100 animate-fadeIn">
              <div className="w-20 h-20 bg-orange-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <svg className="w-10 h-10 text-orange-500 animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
              </div>
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter mb-2">Đang nạp dữ liệu...</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-8 italic">Phân tích & Phân phối thông minh</p>
              <div className="relative h-4 bg-slate-100 rounded-full overflow-hidden mb-4 border border-slate-200">
                <div className="absolute top-0 left-0 h-full bg-orange-500 transition-all duration-300 ease-out shadow-[0_0_15px_rgba(249,115,22,0.3)]" style={{ width: `${importProgress}%` }} />
              </div>
              <span className="text-3xl font-black text-orange-600 tabular-nums">{importProgress}%</span>
            </div>
          </div>
        )}

        {/* API Key Manager Modal */}
        {showKeyModal && (
          <div className="fixed inset-0 z-[100] flex items-start justify-center p-4">
            <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowKeyModal(false)}></div>
            <div className="relative bg-white w-full max-w-lg rounded-[2rem] p-8 !mt-[50px] shadow-2xl border border-slate-200 animate-fadeIn">
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">QUẢN LÝ API KEY</h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">Xoay vòng tự động để tránh giới hạn</p>
                </div>
                <button onClick={() => setShowKeyModal(false)} className="p-2 text-slate-300 hover:text-slate-500 transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>
              <div className="space-y-4">
                <div className="bg-orange-50 border border-orange-100 p-4 rounded-2xl flex gap-3">
                  <svg className="w-5 h-5 text-orange-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  <p className="text-[11px] text-orange-700 leading-relaxed font-medium">Nhập mỗi API Key trên 1 dòng. Hệ thống sẽ sử dụng tuần tự các Key này cho mỗi lượt tạo ảnh để tối ưu tốc độ và quota.</p>
                </div>
                <textarea value={tempKeys} onChange={(e) => setTempKeys(e.target.value)} placeholder="Paste danh sách API Key tại đây..." className="w-full h-64 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-mono focus:ring-4 focus:ring-orange-50 outline-none resize-none" />
                <div className="flex gap-3">
                  <button onClick={() => setShowKeyModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">HỦY BỔ</button>
                  <button onClick={saveKeys} className="flex-1 py-4 bg-orange-600 text-white font-black rounded-2xl text-xs uppercase tracking-widest shadow-lg shadow-orange-100 hover:bg-orange-700 active:scale-95 transition-all">LƯU DANH SÁCH</button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </ErrorBoundary>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { scenes: 2, label: '2 cảnh - 16s' },
  { scenes: 3, label: '3 cảnh - 24s' },
  { scenes: 4, label: '4 cảnh - 32s' },
  { scenes: 5, label: '5 cảnh - 40s' },
  { scenes: 6, label: '6 cảnh - 48s' },
  { scenes: 7, label: '7 cảnh - 56s' },
  { scenes: 8, label: '8 cảnh - 64s' },
];

const TimelapseModule: React.FC = () => {
  const storageKey = "timelapse_project_v2_cumulative";
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [idea, setIdea] = useState('');
  const [sceneCount, setSceneCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Restore from LocalStorage on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setIdea(parsed.idea || '');
        setSceneCount(parsed.sceneCount || 4);
        setBasePreview(parsed.basePreview || null);
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: s.image.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      }
    } catch (e) {
      console.error("Restore Timelapse state fail", e);
    }
  }, []);

  // Save to LocalStorage (Persistent UI state)
  useEffect(() => {
    try {
      const toSave = {
        idea,
        sceneCount,
        basePreview: basePreview?.startsWith('data:') ? basePreview : '',
        segments: segments.map(s => ({
          ...s,
          image: { ...s.image, url: s.image.url?.startsWith('data:') ? s.image.url : '' },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }))
      };
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [idea, sceneCount, basePreview, segments]);

  // HANDLE GLOBAL IMPORT / EXPORT (Sync with Menu Top)
  useEffect(() => {
    const handleExport = async () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: {
          idea: idea,
          sceneCount: sceneCount,
          baseImage: basePreview, // Base64 of the first uploaded image
          regenNote: seg.image.regenNote || ''
        },
        script: seg.content,
        outputImage: seg.image.url || '',
        videoPrompt: seg.videoPrompt.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Timelapse_Project' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      if (!obj) return undefined;
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};

      setIdea(smartFind(inputs, ['idea', 'ý tưởng']) || '');
      setSceneCount(smartFind(inputs, ['sceneCount', 'số cảnh']) || importedData.length);
      setBasePreview(smartFind(inputs, ['baseImage', 'ảnh gốc']) || "");

      const newSegments: TimelapseSegment[] = [];
      const total = importedData.length;

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const itemInputs = smartFind(item, ['inputs', 'input']) || {};

        newSegments.push({
          id: i + 1,
          content: smartFind(item, ['script', 'nội dung', 'text']) || '',
          image: {
            url: smartFind(item, ['outputImage', 'image', 'base64']) || '',
            loading: false,
            regenNote: smartFind(itemInputs, ['regenNote', 'ghi chú']) || ''
          },
          videoPrompt: {
            text: smartFind(item, ['videoPrompt', 'prompt']) || '',
            loading: false,
            visible: !!smartFind(item, ['videoPrompt', 'prompt'])
          }
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 50));
      }
      setSegments(newSegments);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [segments, idea, sceneCount, basePreview]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBaseFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setBasePreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleStart = async () => {
    if (!basePreview || !idea.trim()) {
      alert("Vui lòng tải ảnh hiện trạng và nhập ý tưởng cải tạo.");
      return;
    }
    setIsProcessing(true);
    try {
      const descriptions = await service.generateTimelapseScript(idea, sceneCount);
      const newSegments: TimelapseSegment[] = descriptions.map((desc, i) => ({
        id: i + 1,
        content: desc,
        image: { 
          url: i === 0 ? basePreview : '', 
          loading: false,
          regenNote: ''
        },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setSegments(newSegments);
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];

    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));

    try {
      let basePart = null;
      if (baseFile) {
        basePart = await service.fileToGenerativePart(baseFile);
      } else if (basePreview?.startsWith('data:')) {
        basePart = { mimeType: 'image/png', data: basePreview.split(',')[1] };
      }

      if (!basePart) throw new Error("No base image source");

      // Logic cộng dồn: Lấy ảnh của cảnh ngay trước đó làm tham chiếu
      let prevPart = null;
      if (idx > 0 && segments[idx - 1].image.url) {
        prevPart = { 
          mimeType: 'image/png', 
          data: segments[idx - 1].image.url.split(',')[1] 
        };
      }

      const url = await service.generateTimelapseImage(
        current.content,
        basePart,
        prevPart,
        id === 1
      );

      const finalUrl = url || (id === 1 ? basePreview : '');

      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: finalUrl, loading: false } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi AI' } } : s));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    if (!current.image.url) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateTimelapseVideoPrompt(current.content, current.image.url);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Vui lòng đợi thư viện tải xuống.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        if (base64) {
          zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
          count++;
        }
      }
    });
    if (count === 0) return alert("Không có hình ảnh nào để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadPrompts = () => {
    const text = segments
      .map(s => s.videoPrompt.text.replace(/\n/g, ' ').trim())
      .filter(t => t.length > 0)
      .join('\n');

    if (!text) return alert("Chưa có video prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `timelapse_prompts_${Date.now()}.txt`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Input UI */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">1. Ảnh đầu vào (Khu đất, nhà cũ...)</label>
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="aspect-video border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
              >
                {basePreview ? (
                  <img src={basePreview} className="w-full h-full object-cover" alt="Source" />
                ) : (
                  <div className="text-center opacity-30">
                    <svg className="w-12 h-12 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <span className="text-xs font-black uppercase tracking-widest">Tải ảnh hiện trạng</span>
                  </div>
                )}
                <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
              </div>
            </div>

            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">2. Thời gian video mong muốn</label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {DURATION_OPTIONS.map(opt => (
                  <button 
                    key={opt.scenes}
                    onClick={() => setSceneCount(opt.scenes)}
                    className={`p-3 rounded-xl text-[10px] font-black transition-all border-2 ${sceneCount === opt.scenes ? 'border-orange-500 bg-orange-50 text-orange-600 shadow-md' : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-slate-200'}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="space-y-6 flex flex-col">
            <div className="flex-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">3. Ý tưởng Timelapse (Transformation Idea)</label>
              <textarea 
                value={idea}
                onChange={e => setIdea(e.target.value)}
                placeholder="Ví dụ: Các công nhân dọn dẹp khu đất, rải sỏi, đưa bàn ghế gỗ và mái che tới, tạo hồ cá thả cá, cuối cùng lắp đặt cây xanh trang trí. Kết thúc bằng cảnh trời tối ấm cúng."
                className="w-full h-[calc(100%-40px)] p-6 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-orange-50 focus:border-orange-400 outline-none transition-all font-medium text-sm leading-relaxed resize-none shadow-inner"
              />
            </div>

            <button 
              onClick={handleStart}
              disabled={isProcessing || !basePreview || !idea.trim()}
              className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all disabled:opacity-50 flex items-center justify-center gap-3 uppercase tracking-tighter"
            >
              {isProcessing ? (
                <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> ĐANG PHÂN TÍCH Ý TƯỞNG...</>
              ) : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {/* Results Display */}
      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 shadow-2xl flex flex-col md:flex-row items-center justify-between gap-6">
            <div className="text-center md:text-left">
              <h3 className="text-white font-black text-xl uppercase tracking-tight">Timeline Hành Trình Biến Đổi</h3>
              <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest mt-1">Đã chia {segments.length} phân cảnh thi công</p>
            </div>
            <div className="flex flex-wrap justify-center gap-4">
              <button 
                onClick={downloadAllImages}
                className="px-8 py-4 bg-white text-slate-900 text-[11px] font-black rounded-xl hover:bg-slate-100 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                Tải Bộ Ảnh (ZIP)
              </button>
              <button 
                onClick={downloadPrompts}
                className="px-8 py-4 bg-orange-600 text-white text-[11px] font-black rounded-xl hover:bg-orange-700 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                Tải Bộ Prompt (.TXT)
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg) => (
              <div key={seg.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                  {seg.image.url ? (
                    <img src={seg.image.url} className={`w-full h-full object-cover ${seg.image.loading ? 'blur-sm grayscale opacity-50' : ''}`} alt={`Step ${seg.id}`} />
                  ) : null}

                  {seg.image.loading ? (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/5 backdrop-blur-sm">
                      <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                      <span className="mt-4 text-[10px] font-black text-orange-600 uppercase animate-pulse">Đang dựng hình...</span>
                    </div>
                  ) : !seg.image.url && (
                    <div className="absolute inset-0 flex items-center justify-center opacity-30 font-black uppercase text-[10px] tracking-widest">Sẵn sàng tạo</div>
                  )}

                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-full border border-white/10 shadow-lg">CẢNH #{seg.id}</div>
                </div>

                <div className="p-6 space-y-4 flex flex-col flex-1">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Nội dung thay đổi:</label>
                    <textarea 
                      value={seg.content}
                      onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))}
                      className="w-full h-28 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white transition-all leading-relaxed shadow-inner resize-none"
                    />
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                    <button 
                      onClick={() => handleGenImage(seg.id)}
                      disabled={seg.image.loading}
                      className="py-4 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase tracking-tighter hover:bg-black transition-all flex items-center justify-center gap-1 shadow-md"
                    >
                      {seg.image.loading ? "Chờ..." : (seg.image.url ? "Tạo lại ảnh" : "Vẽ ảnh AI")}
                    </button>
                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={seg.videoPrompt.loading || !seg.image.url}
                      className="py-4 bg-orange-50 text-orange-700 text-[10px] font-black rounded-xl uppercase tracking-tighter border border-orange-200 hover:bg-orange-200 transition-all flex items-center justify-center gap-1 disabled:opacity-30 shadow-sm"
                    >
                      {seg.videoPrompt.loading ? "..." : "Tạo Prompt"}
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-5 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-3">
                      <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Video Prompt Tiếng Việt</span>
                      <button 
                        onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} 
                        className="text-[9px] font-black text-white hover:text-emerald-400 underline"
                      >
                        COPY
                      </button>
                    </div>
                    {seg.videoPrompt.loading ? (
                      <div className="h-10 flex items-center justify-center"><div className="w-5 h-5 border-2 border-emerald-500 border-t-white rounded-full animate-spin"></div></div>
                    ) : (
                      <textarea 
                        value={seg.videoPrompt.text}
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, videoPrompt: { ...s.videoPrompt, text: e.target.value } } : s))}
                        className="w-full bg-transparent text-[10px] text-slate-300 italic leading-snug outline-none resize-none border-none p-0 scrollbar-hide"
                        rows={4}
                      />
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default TimelapseModule;

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { scenes: 2, label: '2 cảnh - 16s' },
  { scenes: 3, label: '3 cảnh - 24s' },
  { scenes: 4, label: '4 cảnh - 32s' },
  { scenes: 5, label: '5 cảnh - 40s' },
  { scenes: 6, label: '6 cảnh - 48s' },
  { scenes: 7, label: '7 cảnh - 56s' },
  { scenes: 8, label: '8 cảnh - 64s' },
];

const TimelapseModule: React.FC = () => {
  const storageKey = "timelapse_project_v2_cumulative";
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [idea, setIdea] = useState('');
  const [sceneCount, setSceneCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Restore from LocalStorage on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setIdea(parsed.idea || '');
        setSceneCount(parsed.sceneCount || 4);
        setBasePreview(parsed.basePreview || null);
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: s.image.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      }
    } catch (e) {
      console.error("Restore Timelapse state fail", e);
    }
  }, []);

  // Save to LocalStorage (Persistent UI state)
  useEffect(() => {
    try {
      const toSave = {
        idea,
        sceneCount,
        basePreview: basePreview?.startsWith('data:') ? basePreview : '',
        segments: segments.map(s => ({
          ...s,
          image: { ...s.image, url: s.image.url?.startsWith('data:') ? s.image.url : '' },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }))
      };
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [idea, sceneCount, basePreview, segments]);

  // HANDLE GLOBAL IMPORT / EXPORT (Sync with Menu Top)
  useEffect(() => {
    const handleExport = async () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: {
          idea: idea,
          sceneCount: sceneCount,
          baseImage: basePreview, // Base64 of the first uploaded image
          regenNote: seg.image.regenNote || ''
        },
        script: seg.content,
        outputImage: seg.image.url || '',
        videoPrompt: seg.videoPrompt.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Timelapse_Project' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      if (!obj) return undefined;
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};

      setIdea(smartFind(inputs, ['idea', 'ý tưởng']) || '');
      setSceneCount(smartFind(inputs, ['sceneCount', 'số cảnh']) || importedData.length);
      setBasePreview(smartFind(inputs, ['baseImage', 'ảnh gốc']) || "");

      const newSegments: TimelapseSegment[] = [];
      const total = importedData.length;

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const itemInputs = smartFind(item, ['inputs', 'input']) || {};

        newSegments.push({
          id: i + 1,
          content: smartFind(item, ['script', 'nội dung', 'text']) || '',
          image: {
            url: smartFind(item, ['outputImage', 'image', 'base64']) || '',
            loading: false,
            regenNote: smartFind(itemInputs, ['regenNote', 'ghi chú']) || ''
          },
          videoPrompt: {
            text: smartFind(item, ['videoPrompt', 'prompt']) || '',
            loading: false,
            visible: !!smartFind(item, ['videoPrompt', 'prompt'])
          }
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 50));
      }
      setSegments(newSegments);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [segments, idea, sceneCount, basePreview]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBaseFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setBasePreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleStart = async () => {
    if (!basePreview || !idea.trim()) {
      alert("Vui lòng tải ảnh hiện trạng và nhập ý tưởng cải tạo.");
      return;
    }
    setIsProcessing(true);
    try {
      const descriptions = await service.generateTimelapseScript(idea, sceneCount);
      const newSegments: TimelapseSegment[] = descriptions.map((desc, i) => ({
        id: i + 1,
        content: desc,
        image: { 
          url: i === 0 ? basePreview : '', 
          loading: false,
          regenNote: ''
        },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setSegments(newSegments);
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];

    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));

    try {
      let basePart = null;
      if (baseFile) {
        basePart = await service.fileToGenerativePart(baseFile);
      } else if (basePreview?.startsWith('data:')) {
        basePart = { mimeType: 'image/png', data: basePreview.split(',')[1] };
      }

      if (!basePart) throw new Error("No base image source");

      // Logic cộng dồn: Lấy ảnh của cảnh ngay trước đó làm tham chiếu
      let prevPart = null;
      if (idx > 0 && segments[idx - 1].image.url) {
        prevPart = { 
          mimeType: 'image/png', 
          data: segments[idx - 1].image.url.split(',')[1] 
        };
      }

      const url = await service.generateTimelapseImage(
        current.content,
        basePart,
        prevPart,
        id === 1
      );

      const finalUrl = url || (id === 1 ? basePreview : '');

      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: finalUrl, loading: false } } : s));
      return finalUrl; // Trả về để dùng cho Bulk
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi AI' } } : s));
      throw e;
    }
  };

  const handleBulkImage = async () => {
    // Chỉ tạo từ cảnh 2 trở đi vì cảnh 1 là ảnh gốc
    for (let i = 2; i <= segments.length; i++) {
        try {
            await handleGenImage(i);
        } catch (e) {
            console.error(`Gặp lỗi tại cảnh ${i}, dừng tạo hàng loạt.`, e);
            break; 
        }
    }
  };

  const handleGenPrompt = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    if (!current.image.url) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateTimelapseVideoPrompt(current.content, current.image.url);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkPrompt = async () => {
    for (const seg of segments) {
        if (seg.image.url) {
            await handleGenPrompt(seg.id);
        }
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Vui lòng đợi thư viện tải xuống.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        if (base64) {
          zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
          count++;
        }
      }
    });
    if (count === 0) return alert("Không có hình ảnh nào để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadPrompts = () => {
    const text = segments
      .map(s => s.videoPrompt.text.replace(/\n/g, ' ').trim())
      .filter(t => t.length > 0)
      .join('\n');

    if (!text) return alert("Chưa có video prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `timelapse_prompts_${Date.now()}.txt`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Input UI */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">1. Ảnh đầu vào (Khu đất, nhà cũ...)</label>
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="aspect-video border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
              >
                {basePreview ? (
                  <img src={basePreview} className="w-full h-full object-cover" alt="Source" />
                ) : (
                  <div className="text-center opacity-30">
                    <svg className="w-12 h-12 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <span className="text-xs font-black uppercase tracking-widest">Tải ảnh hiện trạng</span>
                  </div>
                )}
                <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
              </div>
            </div>

            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">2. Thời gian video mong muốn</label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {DURATION_OPTIONS.map(opt => (
                  <button 
                    key={opt.scenes}
                    onClick={() => setSceneCount(opt.scenes)}
                    className={`p-3 rounded-xl text-[10px] font-black transition-all border-2 ${sceneCount === opt.scenes ? 'border-orange-500 bg-orange-50 text-orange-600 shadow-md' : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-slate-200'}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="space-y-6 flex flex-col">
            <div className="flex-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">3. Ý tưởng Timelapse (Transformation Idea)</label>
              <textarea 
                value={idea}
                onChange={e => setIdea(e.target.value)}
                placeholder="Ví dụ: Các công nhân dọn dẹp khu đất, rải sỏi, đưa bàn ghế gỗ và mái che tới, tạo hồ cá thả cá, cuối cùng lắp đặt cây xanh trang trí. Kết thúc bằng cảnh trời tối ấm cúng."
                className="w-full h-[calc(100%-40px)] p-6 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-orange-50 focus:border-orange-400 outline-none transition-all font-medium text-sm leading-relaxed resize-none shadow-inner"
              />
            </div>

            <button 
              onClick={handleStart}
              disabled={isProcessing || !basePreview || !idea.trim()}
              className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all disabled:opacity-50 flex items-center justify-center gap-3 uppercase tracking-tighter"
            >
              {isProcessing ? (
                <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> ĐANG PHÂN TÍCH Ý TƯỞNG...</>
              ) : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {/* Results Display */}
      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 shadow-2xl flex flex-col lg:flex-row items-center justify-between gap-6">
            <div className="text-center lg:text-left">
              <h3 className="text-white font-black text-xl uppercase tracking-tight">Timeline Hành Trình Biến Đổi</h3>
              <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest mt-1">Đã chia {segments.length} phân cảnh thi công</p>
            </div>
            <div className="flex flex-wrap justify-center gap-4">
              <button 
                onClick={handleBulkImage}
                className="px-6 py-4 bg-orange-600 text-white text-[11px] font-black rounded-xl hover:bg-orange-700 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" /></svg>
                Tự động tạo tất cả ảnh
              </button>
              <button 
                onClick={handleBulkPrompt}
                className="px-6 py-4 bg-slate-700 text-white text-[11px] font-black rounded-xl hover:bg-slate-800 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>
                Tự động viết tất cả prompt
              </button>
              <button 
                onClick={downloadAllImages}
                className="px-6 py-4 bg-white text-slate-900 text-[11px] font-black rounded-xl hover:bg-slate-100 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                Ảnh (ZIP)
              </button>
              <button 
                onClick={downloadPrompts}
                className="px-6 py-4 bg-orange-50 text-orange-700 text-[11px] font-black rounded-xl hover:bg-orange-100 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                Prompt (.TXT)
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg) => (
              <div key={seg.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                  {seg.image.url ? (
                    <img src={seg.image.url} className={`w-full h-full object-cover ${seg.image.loading ? 'blur-sm grayscale opacity-50' : ''}`} alt={`Step ${seg.id}`} />
                  ) : null}

                  {seg.image.loading ? (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/5 backdrop-blur-sm">
                      <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                      <span className="mt-4 text-[10px] font-black text-orange-600 uppercase animate-pulse">Đang dựng hình...</span>
                    </div>
                  ) : !seg.image.url && (
                    <div className="absolute inset-0 flex items-center justify-center opacity-30 font-black uppercase text-[10px] tracking-widest">Sẵn sàng tạo</div>
                  )}

                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-full border border-white/10 shadow-lg">CẢNH #{seg.id}</div>
                </div>

                <div className="p-6 space-y-4 flex flex-col flex-1">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Nội dung thay đổi:</label>
                    <textarea 
                      value={seg.content}
                      onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))}
                      className="w-full h-28 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white transition-all leading-relaxed shadow-inner resize-none"
                    />
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                    <button 
                      onClick={() => handleGenImage(seg.id)}
                      disabled={seg.image.loading}
                      className="py-4 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase tracking-tighter hover:bg-black transition-all flex items-center justify-center gap-1 shadow-md"
                    >
                      {seg.image.loading ? "Chờ..." : (seg.image.url ? "Tạo lại ảnh" : "Vẽ ảnh AI")}
                    </button>
                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={seg.videoPrompt.loading || !seg.image.url}
                      className="py-4 bg-orange-50 text-orange-700 text-[10px] font-black rounded-xl uppercase tracking-tighter border border-orange-200 hover:bg-orange-200 transition-all flex items-center justify-center gap-1 disabled:opacity-30 shadow-sm"
                    >
                      {seg.videoPrompt.loading ? "..." : "Tạo Prompt"}
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-5 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-3">
                      <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Video Prompt Tiếng Việt</span>
                      <button 
                        onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} 
                        className="text-[9px] font-black text-white hover:text-emerald-400 underline"
                      >
                        COPY
                      </button>
                    </div>
                    {seg.videoPrompt.loading ? (
                      <div className="h-10 flex items-center justify-center"><div className="w-5 h-5 border-2 border-emerald-500 border-t-white rounded-full animate-spin"></div></div>
                    ) : (
                      <textarea 
                        value={seg.videoPrompt.text}
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, videoPrompt: { ...s.videoPrompt, text: e.target.value } } : s))}
                        className="w-full bg-transparent text-[10px] text-slate-300 italic leading-snug outline-none resize-none border-none p-0 scrollbar-hide"
                        rows={4}
                      />
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default TimelapseModule;

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { scenes: 2, label: '2 cảnh - 16s' },
  { scenes: 3, label: '3 cảnh - 24s' },
  { scenes: 4, label: '4 cảnh - 32s' },
  { scenes: 5, label: '5 cảnh - 40s' },
  { scenes: 6, label: '6 cảnh - 48s' },
  { scenes: 7, label: '7 cảnh - 56s' },
  { scenes: 8, label: '8 cảnh - 64s' },
];

const TimelapseModule: React.FC = () => {
  const storageKey = "timelapse_project_v3_dual_ref";
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [finalFile, setFinalFile] = useState<File | null>(null);
  const [finalPreview, setFinalPreview] = useState<string | null>(null);
  const [idea, setIdea] = useState('');
  const [sceneCount, setSceneCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const finalInputRef = useRef<HTMLInputElement>(null);

  // Restore from LocalStorage on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setIdea(parsed.idea || '');
        setSceneCount(parsed.sceneCount || 4);
        setBasePreview(parsed.basePreview || null);
        setFinalPreview(parsed.finalPreview || null);
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: s.image.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      }
    } catch (e) {
      console.error("Restore Timelapse state fail", e);
    }
  }, []);

  // Save to LocalStorage (Persistent UI state)
  useEffect(() => {
    try {
      const toSave = {
        idea,
        sceneCount,
        basePreview: basePreview?.startsWith('data:') ? basePreview : '',
        finalPreview: finalPreview?.startsWith('data:') ? finalPreview : '',
        segments: segments.map(s => ({
          ...s,
          image: { ...s.image, url: s.image.url?.startsWith('data:') ? s.image.url : '' },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }))
      };
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [idea, sceneCount, basePreview, finalPreview, segments]);

  // HANDLE GLOBAL IMPORT / EXPORT (Sync with Menu Top)
  useEffect(() => {
    const handleExport = async () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: {
          idea: idea,
          sceneCount: sceneCount,
          baseImage: basePreview,
          finalImage: finalPreview,
          regenNote: seg.image.regenNote || ''
        },
        script: seg.content,
        outputImage: seg.image.url || '',
        videoPrompt: seg.videoPrompt.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Timelapse_Project' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      if (!obj) return undefined;
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};

      setIdea(smartFind(inputs, ['idea', 'ý tưởng']) || '');
      setSceneCount(smartFind(inputs, ['sceneCount', 'số cảnh']) || importedData.length);
      setBasePreview(smartFind(inputs, ['baseImage', 'ảnh gốc', 'ảnh bắt đầu']) || "");
      setFinalPreview(smartFind(inputs, ['finalImage', 'ảnh kết thúc', 'kết quả']) || "");

      const newSegments: TimelapseSegment[] = [];
      const total = importedData.length;

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const itemInputs = smartFind(item, ['inputs', 'input']) || {};

        newSegments.push({
          id: i + 1,
          content: smartFind(item, ['script', 'nội dung', 'text']) || '',
          image: {
            url: smartFind(item, ['outputImage', 'image', 'base64']) || '',
            loading: false,
            regenNote: smartFind(itemInputs, ['regenNote', 'ghi chú']) || ''
          },
          videoPrompt: {
            text: smartFind(item, ['videoPrompt', 'prompt']) || '',
            loading: false,
            visible: !!smartFind(item, ['videoPrompt', 'prompt'])
          }
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 50));
      }
      setSegments(newSegments);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [segments, idea, sceneCount, basePreview, finalPreview]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBaseFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setBasePreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFinalFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setFinalPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleStart = async () => {
    if (!basePreview || !idea.trim()) {
      alert("Vui lòng tải ảnh hiện trạng và nhập ý tưởng cải tạo.");
      return;
    }
    setIsProcessing(true);
    try {
      const descriptions = await service.generateTimelapseScript(idea, sceneCount);
      const newSegments: TimelapseSegment[] = descriptions.map((desc, i) => {
        // Nếu là cảnh cuối và có ảnh kết quả, ta gán luôn URL ảnh kết quả (để người dùng đỡ phải gen lại)
        const isLast = i === sceneCount - 1;
        return {
            id: i + 1,
            content: desc,
            image: { 
              url: i === 0 ? basePreview : (isLast && finalPreview ? finalPreview : ''), 
              loading: false,
              regenNote: ''
            },
            videoPrompt: { text: '', loading: false, visible: false }
        };
      });
      setSegments(newSegments);
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    const isLast = id === segments.length;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));

    try {
      let basePart = null;
      if (baseFile) {
        basePart = await service.fileToGenerativePart(baseFile);
      } else if (basePreview?.startsWith('data:')) {
        basePart = { mimeType: 'image/png', data: basePreview.split(',')[1] };
      }

      if (!basePart) throw new Error("No base image source");

      // Logic cộng dồn: Lấy ảnh của cảnh ngay trước đó làm tham chiếu
      let prevPart = null;
      if (idx > 0 && segments[idx - 1].image.url) {
        prevPart = { 
          mimeType: 'image/png', 
          data: segments[idx - 1].image.url.split(',')[1] 
        };
      }

      // Tham chiếu ảnh kết thúc (nếu có)
      let finalPart = null;
      if (finalFile) {
        finalPart = await service.fileToGenerativePart(finalFile);
      } else if (finalPreview?.startsWith('data:')) {
        finalPart = { mimeType: 'image/png', data: finalPreview.split(',')[1] };
      }

      const url = await service.generateTimelapseImage(
        current.content,
        basePart,
        prevPart,
        finalPart,
        id === 1,
        isLast
      );

      const finalUrl = url || (id === 1 ? basePreview : (isLast && finalPreview ? finalPreview : ''));

      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: finalUrl, loading: false } } : s));
      return finalUrl;
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi AI' } } : s));
      throw e;
    }
  };

  const handleBulkImage = async () => {
    // Chỉ tạo từ cảnh 2 trở đi vì cảnh 1 là ảnh gốc
    // Nếu cảnh cuối đã có ảnh finalPreview rồi thì cũng có thể bỏ qua nếu muốn, nhưng ở đây cứ để tạo hàng loạt cho đồng nhất style
    for (let i = 2; i <= segments.length; i++) {
        try {
            await handleGenImage(i);
        } catch (e) {
            console.error(`Gặp lỗi tại cảnh ${i}, dừng tạo hàng loạt.`, e);
            break; 
        }
    }
  };

  const handleGenPrompt = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    if (!current.image.url) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateTimelapseVideoPrompt(current.content, current.image.url);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkPrompt = async () => {
    for (const seg of segments) {
        if (seg.image.url) {
            await handleGenPrompt(seg.id);
        }
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Vui lòng đợi thư viện tải xuống.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        if (base64) {
          zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
          count++;
        }
      }
    });
    if (count === 0) return alert("Không có hình ảnh nào để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadPrompts = () => {
    const text = segments
      .map(s => s.videoPrompt.text.replace(/\n/g, ' ').trim())
      .filter(t => t.length > 0)
      .join('\n');

    if (!text) return alert("Chưa có video prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `timelapse_prompts_${Date.now()}.txt`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Input UI */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">1. Hình ảnh tham chiếu (Ảnh đầu & Ảnh cuối)</label>
              <div className="grid grid-cols-2 gap-4">
                {/* Column 1: Start Image */}
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {basePreview ? (
                    <img src={basePreview} className="w-full h-full object-cover" alt="Source" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Ảnh hiện trạng</span>
                    </div>
                    )}
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
                    {basePreview && <div className="absolute bottom-2 left-2 bg-black/60 text-white text-[8px] font-black px-2 py-1 rounded uppercase">Bắt đầu</div>}
                </div>

                {/* Column 2: End Image */}
                <div 
                    onClick={() => finalInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {finalPreview ? (
                    <img src={finalPreview} className="w-full h-full object-cover" alt="Final Goal" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Kết quả cuối (Tùy chọn)</span>
                    </div>
                    )}
                    <input type="file" ref={finalInputRef} onChange={handleFinalUpload} className="hidden" accept="image/*" />
                    {finalPreview && <div className="absolute bottom-2 left-2 bg-orange-600 text-white text-[8px] font-black px-2 py-1 rounded uppercase">Kết thúc</div>}
                </div>
              </div>
            </div>

            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">2. Thời gian video mong muốn</label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {DURATION_OPTIONS.map(opt => (
                  <button 
                    key={opt.scenes}
                    onClick={() => setSceneCount(opt.scenes)}
                    className={`p-3 rounded-xl text-[10px] font-black transition-all border-2 ${sceneCount === opt.scenes ? 'border-orange-500 bg-orange-50 text-orange-600 shadow-md' : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-slate-200'}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="space-y-6 flex flex-col">
            <div className="flex-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">3. Ý tưởng Timelapse (Transformation Idea)</label>
              <textarea 
                value={idea}
                onChange={e => setIdea(e.target.value)}
                placeholder="Ví dụ: Các công nhân dọn dẹp khu đất, rải sỏi, đưa bàn ghế gỗ và mái che tới, tạo hồ cá thả cá, cuối cùng lắp đặt cây xanh trang trí. Kết thúc bằng cảnh trời tối ấm cúng."
                className="w-full h-[calc(100%-40px)] p-6 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-orange-50 focus:border-orange-400 outline-none transition-all font-medium text-sm leading-relaxed resize-none shadow-inner"
              />
            </div>

            <button 
              onClick={handleStart}
              disabled={isProcessing || !basePreview || !idea.trim()}
              className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all disabled:opacity-50 flex items-center justify-center gap-3 uppercase tracking-tighter"
            >
              {isProcessing ? (
                <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> ĐANG PHÂN TÍCH Ý TƯỞNG...</>
              ) : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {/* Results Display */}
      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 shadow-2xl flex flex-col lg:flex-row items-center justify-between gap-6">
            <div className="text-center lg:text-left">
              <h3 className="text-white font-black text-xl uppercase tracking-tight">Timeline Hành Trình Biến Đổi</h3>
              <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest mt-1">Đã chia {segments.length} phân cảnh thi công</p>
            </div>
            <div className="flex flex-wrap justify-center gap-4">
              <button 
                onClick={handleBulkImage}
                className="px-6 py-4 bg-orange-600 text-white text-[11px] font-black rounded-xl hover:bg-orange-700 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" /></svg>
                Tự động tạo tất cả ảnh
              </button>
              <button 
                onClick={handleBulkPrompt}
                className="px-6 py-4 bg-slate-700 text-white text-[11px] font-black rounded-xl hover:bg-slate-800 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>
                Tự động viết tất cả prompt
              </button>
              <button 
                onClick={downloadAllImages}
                className="px-6 py-4 bg-white text-slate-900 text-[11px] font-black rounded-xl hover:bg-slate-100 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                Ảnh (ZIP)
              </button>
              <button 
                onClick={downloadPrompts}
                className="px-6 py-4 bg-orange-50 text-orange-700 text-[11px] font-black rounded-xl hover:bg-orange-100 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                Prompt (.TXT)
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg) => (
              <div key={seg.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                  {seg.image.url ? (
                    <img src={seg.image.url} className={`w-full h-full object-cover ${seg.image.loading ? 'blur-sm grayscale opacity-50' : ''}`} alt={`Step ${seg.id}`} />
                  ) : null}

                  {seg.image.loading ? (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/5 backdrop-blur-sm">
                      <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                      <span className="mt-4 text-[10px] font-black text-orange-600 uppercase animate-pulse">Đang dựng hình...</span>
                    </div>
                  ) : !seg.image.url && (
                    <div className="absolute inset-0 flex items-center justify-center opacity-30 font-black uppercase text-[10px] tracking-widest">Sẵn sàng tạo</div>
                  )}

                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-full border border-white/10 shadow-lg">CẢNH #{seg.id}</div>
                </div>

                <div className="p-6 space-y-4 flex flex-col flex-1">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Nội dung thay đổi:</label>
                    <textarea 
                      value={seg.content}
                      onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))}
                      className="w-full h-28 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white transition-all leading-relaxed shadow-inner resize-none"
                    />
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                    <button 
                      onClick={() => handleGenImage(seg.id)}
                      disabled={seg.image.loading}
                      className="py-4 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase tracking-tighter hover:bg-black transition-all flex items-center justify-center gap-1 shadow-md"
                    >
                      {seg.image.loading ? "Chờ..." : (seg.image.url ? "Tạo lại ảnh" : "Vẽ ảnh AI")}
                    </button>
                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={seg.videoPrompt.loading || !seg.image.url}
                      className="py-4 bg-orange-50 text-orange-700 text-[10px] font-black rounded-xl uppercase tracking-tighter border border-orange-200 hover:bg-orange-200 transition-all flex items-center justify-center gap-1 disabled:opacity-30 shadow-sm"
                    >
                      {seg.videoPrompt.loading ? "..." : "Tạo Prompt"}
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-5 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-3">
                      <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Video Prompt Tiếng Việt</span>
                      <button 
                        onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} 
                        className="text-[9px] font-black text-white hover:text-emerald-400 underline"
                      >
                        COPY
                      </button>
                    </div>
                    {seg.videoPrompt.loading ? (
                      <div className="h-10 flex items-center justify-center"><div className="w-5 h-5 border-2 border-emerald-500 border-t-white rounded-full animate-spin"></div></div>
                    ) : (
                      <textarea 
                        value={seg.videoPrompt.text}
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, videoPrompt: { ...s.videoPrompt, text: e.target.value } } : s))}
                        className="w-full bg-transparent text-[10px] text-slate-300 italic leading-snug outline-none resize-none border-none p-0 scrollbar-hide"
                        rows={4}
                      />
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default TimelapseModule;

import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Task 1: Chia ý tưởng thành các phân cảnh kịch bản dựa trên số lượng cảnh.
 */
export const generateTimelapseScript = async (idea: string, sceneCount: number): Promise<string[]> => {
  const ai = getAiClient();
  const prompt = `
    Nhiệm vụ: Phân tích ý tưởng cải tạo/tiến trình (timelapse) sau: "${idea}".
    Hãy chia tiến trình này thành ĐÚNG ${sceneCount} phân cảnh logic để tạo thành một video timelapse hoàn chỉnh.

    YÊU CẦU:
    1. Cảnh 1: BẮT BUỘC là hiện trạng ban đầu (khớp với hình ảnh người dùng tải lên).
    2. Các cảnh tiếp theo: Thể hiện sự thay đổi CỘNG DỒN dần dần, từng bước một.
    3. Cảnh cuối cùng: Kết quả hoàn thiện theo ý tưởng của người dùng.
    4. Mỗi mô tả cảnh phải ngắn gọn (dưới 150 ký tự), mô tả sự thay đổi so với cảnh trước.
    5. Trả về mảng JSON các chuỗi ký tự (Tiếng Việt).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (error) {
    console.error("Script generation error", error);
    return Array(sceneCount).fill("Mô tả phân cảnh...");
  }
};

/**
 * Task 2: Tạo hình ảnh cho phân cảnh timelapse (Logic cộng dồn và Dual Reference).
 */
export const generateTimelapseImage = async (
  sceneDescription: string,
  baseImagePart: any,
  previousImagePart: any | null,
  finalGoalPart: any | null,
  isFirst: boolean,
  isLast: boolean
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";

  // Cảnh 1 trả về ảnh gốc (logic ở module UI xử lý để tối ưu)
  if (isFirst && !previousImagePart) {
      return ""; 
  }

  const prompt = `
    STYLE: Photorealistic RAW PHOTO, 8k resolution, cinematic lighting, ultra-detailed.
    RATIO: 9:16 portrait.

    TASK (CRITICAL): This is a scene in a TIMELAPSE series. 
    1. You MUST KEEP 100% of the original composition, camera angle, furniture, and structures from the REFERENCE_IMAGE provided (START_STATE).
    2. ONLY ADD or MODIFY the specific details described here: "${sceneDescription}".
    3. The changes must look like a natural progression from the previous state towards the goal.
    ${finalGoalPart ? '4. GUIDE: The end goal should look like the provided GOAL_IMAGE. Ensure this current scene is a logical step toward that result.' : ''}
    5. NO TEXT, NO LOGOS, NO WATERMARKS.
  `;

  // Gửi ảnh của phân cảnh trước đó làm tham chiếu chính (để cộng dồn)
  // Nếu có ảnh mục tiêu (Final Goal), ta gửi kèm để AI định hướng tốt hơn
  const contents: any[] = [{ text: prompt }];

  // PRIMARY REFERENCE (Current State to build upon)
  if (previousImagePart) {
      contents.push({ inlineData: previousImagePart });
  } else {
      contents.push({ inlineData: baseImagePart });
  }

  // SECONDARY REFERENCE (Goal guidance)
  if (finalGoalPart) {
    contents.push({ inlineData: finalGoalPart });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("Fail to generate image");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) {
    console.error("Image generation error", error);
    throw error;
  }
};

/**
 * Task 3: Tạo video prompt chi tiết cho phân cảnh.
 */
export const generateTimelapseVideoPrompt = async (
  description: string,
  imageUrl: string
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Dựa trên mô tả cảnh timelapse: "${description}" và hình ảnh tham chiếu đính kèm.
    Hãy viết một đoạn prompt mô tả chuyển động chi tiết (bằng TIẾNG VIỆT) cho AI Video (VEO-3) dài 8 giây.

    CẤU TRÚC PROMPT (VIẾT LIỀM MẠCH TRÊN 1 DÒNG):
    Mô tả chi tiết hành động đang xảy ra (VD: các tia nắng thay đổi, công nhân đang làm việc, cây cối khẽ rung rinh...), bối cảnh bám sát hình ảnh, ánh sáng điện ảnh, chuyển động máy ảnh pan/zoom mượt mà. 
    Thông số: Tỉ lệ 9:16, 4K, Realistic, Cinematic Lighting, 60fps.

    YÊU CẦU: Trả về ĐÚNG 1 DÒNG duy nhất bằng Tiếng Việt.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { 
        parts: [
          { text: prompt },
          { inlineData: { mimeType: 'image/png', data: imageUrl.split(',')[1] } }
        ] 
      }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return "Lỗi khi tạo video prompt.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { scenes: 2, label: '2 cảnh - 16s' },
  { scenes: 3, label: '3 cảnh - 24s' },
  { scenes: 4, label: '4 cảnh - 32s' },
  { scenes: 5, label: '5 cảnh - 40s' },
  { scenes: 6, label: '6 cảnh - 48s' },
  { scenes: 7, label: '7 cảnh - 56s' },
  { scenes: 8, label: '8 cảnh - 64s' },
];

const TimelapseModule: React.FC = () => {
  const storageKey = "timelapse_project_v3_dual_ref";
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [finalFile, setFinalFile] = useState<File | null>(null);
  const [finalPreview, setFinalPreview] = useState<string | null>(null);
  const [idea, setIdea] = useState('');
  const [sceneCount, setSceneCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const finalInputRef = useRef<HTMLInputElement>(null);

  // Restore from LocalStorage on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setIdea(parsed.idea || '');
        setSceneCount(parsed.sceneCount || 4);
        setBasePreview(parsed.basePreview || null);
        setFinalPreview(parsed.finalPreview || null);
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: s.image.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      }
    } catch (e) {
      console.error("Restore Timelapse state fail", e);
    }
  }, []);

  // Save to LocalStorage (Persistent UI state)
  useEffect(() => {
    try {
      const toSave = {
        idea,
        sceneCount,
        basePreview: basePreview?.startsWith('data:') ? basePreview : '',
        finalPreview: finalPreview?.startsWith('data:') ? finalPreview : '',
        segments: segments.map(s => ({
          ...s,
          image: { ...s.image, url: s.image.url?.startsWith('data:') ? s.image.url : '' },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }))
      };
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [idea, sceneCount, basePreview, finalPreview, segments]);

  // HANDLE GLOBAL IMPORT / EXPORT (Sync with Menu Top)
  useEffect(() => {
    const handleExport = async () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: {
          idea: idea,
          sceneCount: sceneCount,
          baseImage: basePreview,
          finalImage: finalPreview,
          regenNote: seg.image.regenNote || ''
        },
        script: seg.content,
        outputImage: seg.image.url || '',
        videoPrompt: seg.videoPrompt.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Timelapse_Project' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      if (!obj) return undefined;
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};

      setIdea(smartFind(inputs, ['idea', 'ý tưởng']) || '');
      setSceneCount(smartFind(inputs, ['sceneCount', 'số cảnh']) || importedData.length);
      setBasePreview(smartFind(inputs, ['baseImage', 'ảnh gốc', 'ảnh bắt đầu']) || "");
      setFinalPreview(smartFind(inputs, ['finalImage', 'ảnh kết thúc', 'kết quả']) || "");

      const newSegments: TimelapseSegment[] = [];
      const total = importedData.length;

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const itemInputs = smartFind(item, ['inputs', 'input']) || {};

        newSegments.push({
          id: i + 1,
          content: smartFind(item, ['script', 'nội dung', 'text']) || '',
          image: {
            url: smartFind(item, ['outputImage', 'image', 'base64']) || '',
            loading: false,
            regenNote: smartFind(itemInputs, ['regenNote', 'ghi chú']) || ''
          },
          videoPrompt: {
            text: smartFind(item, ['videoPrompt', 'prompt']) || '',
            loading: false,
            visible: !!smartFind(item, ['videoPrompt', 'prompt'])
          }
        });

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 50));
      }
      setSegments(newSegments);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [segments, idea, sceneCount, basePreview, finalPreview]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBaseFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setBasePreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFinalFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setFinalPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleStart = async () => {
    if (!basePreview || !idea.trim()) {
      alert("Vui lòng tải ảnh hiện trạng và nhập ý tưởng cải tạo.");
      return;
    }
    setIsProcessing(true);
    try {
      const descriptions = await service.generateTimelapseScript(idea, sceneCount);
      const newSegments: TimelapseSegment[] = descriptions.map((desc, i) => {
        // Nếu là cảnh cuối và có ảnh kết quả, ta gán luôn URL ảnh kết quả (để người dùng đỡ phải gen lại)
        const isLast = i === sceneCount - 1;
        return {
            id: i + 1,
            content: desc,
            image: { 
              url: i === 0 ? basePreview : (isLast && finalPreview ? finalPreview : ''), 
              loading: false,
              regenNote: ''
            },
            videoPrompt: { text: '', loading: false, visible: false }
        };
      });
      setSegments(newSegments);
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    const isLast = id === segments.length;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));

    try {
      let basePart = null;
      if (baseFile) {
        basePart = await service.fileToGenerativePart(baseFile);
      } else if (basePreview?.startsWith('data:')) {
        basePart = { mimeType: 'image/png', data: basePreview.split(',')[1] };
      }

      if (!basePart) throw new Error("No base image source");

      // Logic cộng dồn: Lấy ảnh của cảnh ngay trước đó làm tham chiếu
      let prevPart = null;
      if (idx > 0 && segments[idx - 1].image.url) {
        prevPart = { 
          mimeType: 'image/png', 
          data: segments[idx - 1].image.url.split(',')[1] 
        };
      }

      // Tham chiếu ảnh kết thúc (nếu có)
      let finalPart = null;
      if (finalFile) {
        finalPart = await service.fileToGenerativePart(finalFile);
      } else if (finalPreview?.startsWith('data:')) {
        finalPart = { mimeType: 'image/png', data: finalPreview.split(',')[1] };
      }

      const url = await service.generateTimelapseImage(
        current.content,
        basePart,
        prevPart,
        finalPart,
        id === 1,
        isLast
      );

      const finalUrl = url || (id === 1 ? basePreview : (isLast && finalPreview ? finalPreview : ''));

      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: finalUrl, loading: false } } : s));
      return finalUrl;
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi AI' } } : s));
      throw e;
    }
  };

  const handleGenPrompt = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    if (!current.image.url) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateTimelapseVideoPrompt(current.content, current.image.url);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkPrompt = async () => {
    for (const seg of segments) {
        if (seg.image.url) {
            await handleGenPrompt(seg.id);
        }
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Vui lòng đợi thư viện tải xuống.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        if (base64) {
          zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
          count++;
        }
      }
    });
    if (count === 0) return alert("Không có hình ảnh nào để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadPrompts = () => {
    const text = segments
      .map(s => s.videoPrompt.text.replace(/\n/g, ' ').trim())
      .filter(t => t.length > 0)
      .join('\n');

    if (!text) return alert("Chưa có video prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `timelapse_prompts_${Date.now()}.txt`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Input UI */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">1. Hình ảnh tham chiếu (Ảnh đầu & Ảnh cuối)</label>
              <div className="grid grid-cols-2 gap-4">
                {/* Column 1: Start Image */}
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {basePreview ? (
                    <img src={basePreview} className="w-full h-full object-cover" alt="Source" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Ảnh hiện trạng</span>
                    </div>
                    )}
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
                    {basePreview && <div className="absolute bottom-2 left-2 bg-black/60 text-white text-[8px] font-black px-2 py-1 rounded uppercase">Bắt đầu</div>}
                </div>

                {/* Column 2: End Image */}
                <div 
                    onClick={() => finalInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {finalPreview ? (
                    <img src={finalPreview} className="w-full h-full object-cover" alt="Final Goal" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Kết quả cuối (Tùy chọn)</span>
                    </div>
                    )}
                    <input type="file" ref={finalInputRef} onChange={handleFinalUpload} className="hidden" accept="image/*" />
                    {finalPreview && <div className="absolute bottom-2 left-2 bg-orange-600 text-white text-[8px] font-black px-2 py-1 rounded uppercase">Kết thúc</div>}
                </div>
              </div>
            </div>

            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">2. Thời gian video mong muốn</label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {DURATION_OPTIONS.map(opt => (
                  <button 
                    key={opt.scenes}
                    onClick={() => setSceneCount(opt.scenes)}
                    className={`p-3 rounded-xl text-[10px] font-black transition-all border-2 ${sceneCount === opt.scenes ? 'border-orange-500 bg-orange-50 text-orange-600 shadow-md' : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-slate-200'}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="space-y-6 flex flex-col">
            <div className="flex-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">3. Ý tưởng Timelapse (Transformation Idea)</label>
              <textarea 
                value={idea}
                onChange={e => setIdea(e.target.value)}
                placeholder="Ví dụ: Các công nhân dọn dẹp khu đất, rải sỏi, đưa bàn ghế gỗ và mái che tới, tạo hồ cá thả cá, cuối cùng lắp đặt cây xanh trang trí. Kết thúc bằng cảnh trời tối ấm cúng."
                className="w-full h-[calc(100%-40px)] p-6 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-orange-50 focus:border-orange-400 outline-none transition-all font-medium text-sm leading-relaxed resize-none shadow-inner"
              />
            </div>

            <button 
              onClick={handleStart}
              disabled={isProcessing || !basePreview || !idea.trim()}
              className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all disabled:opacity-50 flex items-center justify-center gap-3 uppercase tracking-tighter"
            >
              {isProcessing ? (
                <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> ĐANG PHÂN TÍCH Ý TƯỞNG...</>
              ) : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {/* Results Display */}
      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 shadow-2xl flex flex-col lg:flex-row items-center justify-between gap-6">
            <div className="text-center lg:text-left">
              <h3 className="text-white font-black text-xl uppercase tracking-tight">Timeline Hành Trình Biến Đổi</h3>
