                        className="text-[9px] font-black text-white hover:text-emerald-400 underline"
                      >
                        COPY
                      </button>
                    </div>
                    {seg.videoPrompt.loading ? (
                      <div className="h-10 flex items-center justify-center"><div className="w-5 h-5 border-2 border-emerald-500 border-t-white rounded-full animate-spin"></div></div>
                    ) : (
                      <textarea 
                        value={seg.videoPrompt.text}
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, videoPrompt: { ...s.videoPrompt, text: e.target.value } } : s))}
                        className="w-full bg-transparent text-[10px] text-slate-300 italic leading-snug outline-none resize-none border-none p-0 scrollbar-hide"
                        rows={4}
                      />
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

