import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Task 1: Chia ý tưởng thành các phân cảnh kịch bản dựa trên số lượng cảnh.
 */
export const generateTimelapseScript = async (idea: string, sceneCount: number): Promise<string[]> => {
  const ai = getAiClient();
  const prompt = `
    Nhiệm vụ: Phân tích ý tưởng cải tạo/tiến trình (timelapse) sau: "${idea}".
    Hãy chia tiến trình này thành ĐÚNG ${sceneCount} phân cảnh logic để tạo thành một video timelapse hoàn chỉnh.

    YÊU CẦU:
    1. Cảnh 1: BẮT BUỘC là hiện trạng ban đầu.
    2. Các cảnh tiếp theo: Thể hiện sự thay đổi CỘNG DỒN dần dần, từng bước một.
    3. Cảnh cuối cùng: Kết quả hoàn thiện theo ý tưởng.
    4. Mỗi mô tả cảnh phải ngắn gọn (dưới 150 ký tự), mô tả sự thay đổi cụ thể so với cảnh trước.
    5. Trả về mảng JSON các chuỗi ký tự (Tiếng Việt).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (error) {
    console.error("Script generation error", error);
    return Array(sceneCount).fill("Mô tả phân cảnh...");
  }
};

/**
 * Task 2: Tạo hình ảnh cho phân cảnh timelapse (Strict Continuity & Goal Matching).
 */
export const generateTimelapseImage = async (
  sceneDescription: string,
  baseImagePart: any,
  previousImagePart: any | null,
  finalGoalPart: any | null,
  isFirst: boolean,
  isLast: boolean
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";

  // Cảnh 1 mặc định dùng ảnh gốc
  if (isFirst) return ""; 

  const prompt = `
    STYLE: Photorealistic RAW PHOTO, 8k resolution, cinematic lighting, ultra-detailed architectural visualization.
    RATIO: 9:16 portrait.

    TASK: You are generating an intermediate frame for a seamless TIMELAPSE video.

    1. !!! STRICT CONTINUITY RULE (MANDATORY) !!!: 
       - You MUST use the "PREVIOUS_IMAGE" as your absolute base. 
       - Keep 100% of the camera angle, focal length, fixed structures (walls, floor, ceiling), and lighting source positions from PREVIOUS_IMAGE.
       - The image must look like a direct continuation of the previous state.

    2. !!! GOAL MATCHING RULE (MANDATORY) !!!:
       - Reference the "FINAL_GOAL_IMAGE" to understand the target aesthetic and objects.
       - ONLY ADD or MODIFY details to reflect this specific step: "${sceneDescription}".
       - The added elements must look identical in material and style to those in the FINAL_GOAL_IMAGE.

    3. !!! VISUAL FIDELITY !!!:
       - NO TEXT, NO LOGOS, NO WATERMARKS.
       - Everything must be perfectly blended and photorealistic.
  `;

  const contents: any[] = [{ text: prompt }];

  // Tham chiếu ảnh ngay trước đó (Quan trọng nhất để không bị nhảy hình)
  if (previousImagePart) {
      contents.push({ inlineData: previousImagePart }); // Đóng vai trò là PREVIOUS_IMAGE
  } else {
      contents.push({ inlineData: baseImagePart });
  }

  // Tham chiếu ảnh đích (Để AI biết cuối cùng nó sẽ thành cái gì)
  if (finalGoalPart) {
    contents.push({ inlineData: finalGoalPart }); // Đóng vai trò là FINAL_GOAL_IMAGE
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("Fail to generate image");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) {
    console.error("Image generation error", error);
    throw error;
  }
};

/**
 * Task 3: Tạo video prompt chi tiết cho phân cảnh.
 */
export const generateTimelapseVideoPrompt = async (
  description: string,
  imageUrl: string
): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Dựa trên hình ảnh tham chiếu, hãy viết 1 đoạn prompt tiếng Anh (VEO-3) cho video timelapse 8 giây.
    Mô tả sự thay đổi: "${description}".
    YÊU CẦU: Camera cố định (Static camera), mô tả sự xuất hiện của các vật thể mới một cách mượt mà như đang thi công thật. Ánh sáng tự nhiên. 
    Trả về ĐÚNG 1 DÒNG duy nhất bằng Tiếng Anh.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { 
        parts: [
          { text: prompt },
          { inlineData: { mimeType: 'image/png', data: imageUrl.split(',')[1] } }
        ] 
      }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return "Error generating video prompt.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { scenes: 2, label: '2 cảnh - 16s' },
  { scenes: 3, label: '3 cảnh - 24s' },
  { scenes: 4, label: '4 cảnh - 32s' },
  { scenes: 5, label: '5 cảnh - 40s' },
  { scenes: 6, label: '6 cảnh - 48s' },
  { scenes: 7, label: '7 cảnh - 56s' },
  { scenes: 8, label: '8 cảnh - 64s' },
];

const TimelapseModule: React.FC = () => {
  const storageKey = "timelapse_project_v3_dual_ref";
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [finalFile, setFinalFile] = useState<File | null>(null);
  const [finalPreview, setFinalPreview] = useState<string | null>(null);
  const [idea, setIdea] = useState('');
  const [sceneCount, setSceneCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const segmentsRef = useRef<TimelapseSegment[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const finalInputRef = useRef<HTMLInputElement>(null);

  // Sync ref with state to always have latest data in async calls
  useEffect(() => {
    segmentsRef.current = segments;
  }, [segments]);

  // Restore from LocalStorage on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setIdea(parsed.idea || '');
        setSceneCount(parsed.sceneCount || 4);
        setBasePreview(parsed.basePreview || null);
        setFinalPreview(parsed.finalPreview || null);
        const restoredSegments = (parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: s.image.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }));
        setSegments(restoredSegments);
        segmentsRef.current = restoredSegments;
      }
    } catch (e) {
      console.error("Restore Timelapse state fail", e);
    }
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    try {
      const toSave = {
        idea,
        sceneCount,
        basePreview: basePreview?.startsWith('data:') ? basePreview : '',
        finalPreview: finalPreview?.startsWith('data:') ? finalPreview : '',
        segments: segments.map(s => ({
          ...s,
          image: { ...s.image, url: s.image.url?.startsWith('data:') ? s.image.url : '' },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }))
      };
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [idea, sceneCount, basePreview, finalPreview, segments]);

  // Handle Export/Import
  useEffect(() => {
    const handleExport = () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: { idea, sceneCount, baseImage: basePreview, finalImage: finalPreview },
        script: seg.content,
        outputImage: seg.image.url || '',
        videoPrompt: seg.videoPrompt.text || ''
      }));
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Timelapse_Project' } 
      }));
    };
    const handleImport = async (e: any) => {
        // Simple import logic for demo
        const importedData = e.detail;
        if (!Array.isArray(importedData)) return;
        setIdea(importedData[0]?.inputs?.idea || '');
        setSegments(importedData.map((item: any, idx: number) => ({
            id: idx + 1,
            content: item.script || '',
            image: { url: item.outputImage || '', loading: false },
            videoPrompt: { text: item.videoPrompt || '', loading: false, visible: !!item.videoPrompt }
        })));
    };
    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [segments, idea, sceneCount, basePreview, finalPreview]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBaseFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setBasePreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFinalFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setFinalPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleStart = async () => {
    if (!basePreview || !idea.trim()) {
      alert("Vui lòng tải ảnh hiện trạng và nhập ý tưởng cải tạo.");
      return;
    }
    setIsProcessing(true);
    try {
      const descriptions = await service.generateTimelapseScript(idea, sceneCount);
      const newSegments: TimelapseSegment[] = descriptions.map((desc, i) => ({
        id: i + 1,
        content: desc,
        image: { 
          url: i === 0 ? basePreview : '', 
          loading: false,
          regenNote: ''
        },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setSegments(newSegments);
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const idx = id - 1;
    const currentSegments = segmentsRef.current;
    const current = currentSegments[idx];
    const isLast = id === currentSegments.length;

    // Set loading state
    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));

    try {
      // 1. Ảnh gốc ban đầu
      let basePart = null;
      if (baseFile) {
        basePart = await service.fileToGenerativePart(baseFile);
      } else if (basePreview?.startsWith('data:')) {
        basePart = { mimeType: 'image/png', data: basePreview.split(',')[1] };
      }

      // 2. Ảnh ngay phía trước (Quan trọng nhất để giữ cấu trúc)
      let prevPart = null;
      const prevImage = currentSegments[idx - 1]?.image?.url;
      if (idx > 0 && prevImage) {
        prevPart = { 
          mimeType: 'image/png', 
          data: prevImage.split(',')[1] 
        };
      }

      // 3. Ảnh kết thúc mục tiêu (Để AI không bị lạc đường)
      let finalPart = null;
      if (finalFile) {
        finalPart = await service.fileToGenerativePart(finalFile);
      } else if (finalPreview?.startsWith('data:')) {
        finalPart = { mimeType: 'image/png', data: finalPreview.split(',')[1] };
      }

      const url = await service.generateTimelapseImage(
        current.content,
        basePart,
        prevPart,
        finalPart,
        id === 1,
        isLast
      );

      const finalUrl = url || (id === 1 ? basePreview : '');

      setSegments(prev => {
          const next = prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: finalUrl, loading: false } } : s);
          segmentsRef.current = next; // Update ref immediately
          return next;
      });

      return finalUrl;
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi AI' } } : s));
      throw e;
    }
  };

  const handleGenPrompt = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    if (!current.image.url) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateTimelapseVideoPrompt(current.content, current.image.url);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkPrompt = async () => {
    for (const seg of segments) {
        if (seg.image.url) {
            await handleGenPrompt(seg.id);
        }
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Vui lòng đợi thư viện tải xuống.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        if (base64) {
          zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
          count++;
        }
      }
    });
    if (count === 0) return alert("Không có hình ảnh nào để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadPrompts = () => {
    const text = segments
      .map(s => s.videoPrompt.text.replace(/\n/g, ' ').trim())
      .filter(t => t.length > 0)
      .join('\n');
    if (!text) return alert("Chưa có video prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `timelapse_prompts_${Date.now()}.txt`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Input UI */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">1. Hình ảnh tham chiếu (Ảnh đầu & Ảnh cuối)</label>
              <div className="grid grid-cols-2 gap-4">
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {basePreview ? (
                    <img src={basePreview} className="w-full h-full object-cover" alt="Source" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Ảnh hiện trạng</span>
                    </div>
                    )}
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
                    {basePreview && <div className="absolute bottom-2 left-2 bg-black/60 text-white text-[8px] font-black px-2 py-1 rounded uppercase">Bắt đầu</div>}
                </div>

                <div 
                    onClick={() => finalInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {finalPreview ? (
                    <img src={finalPreview} className="w-full h-full object-cover" alt="Final Goal" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Kết quả cuối (Tùy chọn)</span>
                    </div>
                    )}
                    <input type="file" ref={finalInputRef} onChange={handleFinalUpload} className="hidden" accept="image/*" />
                    {finalPreview && <div className="absolute bottom-2 left-2 bg-orange-600 text-white text-[8px] font-black px-2 py-1 rounded uppercase">Kết thúc</div>}
                </div>
              </div>
            </div>

            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">2. Thời gian video mong muốn</label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                {DURATION_OPTIONS.map(opt => (
                  <button 
                    key={opt.scenes}
                    onClick={() => setSceneCount(opt.scenes)}
                    className={`p-3 rounded-xl text-[10px] font-black transition-all border-2 ${sceneCount === opt.scenes ? 'border-orange-500 bg-orange-50 text-orange-600 shadow-md' : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-slate-200'}`}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="space-y-6 flex flex-col">
            <div className="flex-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">3. Ý tưởng Timelapse (Transformation Idea)</label>
              <textarea 
                value={idea}
                onChange={e => setIdea(e.target.value)}
                placeholder="Ví dụ: Các công nhân dọn dẹp khu đất, rải sỏi, đưa bàn ghế gỗ và mái che tới, tạo hồ cá thả cá, cuối cùng lắp đặt cây xanh trang trí."
                className="w-full h-[calc(100%-40px)] p-6 bg-slate-50 border border-slate-200 rounded-3xl focus:ring-4 focus:ring-orange-50 focus:border-orange-400 outline-none transition-all font-medium text-sm leading-relaxed resize-none shadow-inner"
              />
            </div>
            <button 
              onClick={handleStart}
              disabled={isProcessing || !basePreview || !idea.trim()}
              className="w-full py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl shadow-orange-100 hover:bg-orange-700 transition-all disabled:opacity-50 flex items-center justify-center gap-3 uppercase tracking-tighter"
            >
              {isProcessing ? (
                <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> ĐANG PHÂN TÍCH Ý TƯỞNG...</>
              ) : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {/* Results Display */}
      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 shadow-2xl flex flex-col lg:flex-row items-center justify-between gap-6">
            <div className="text-center lg:text-left">
              <h3 className="text-white font-black text-xl uppercase tracking-tight">Timeline Hành Trình Biến Đổi</h3>
              <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest mt-1">Đã chia {segments.length} phân cảnh thi công</p>
            </div>
            <div className="flex flex-wrap justify-center gap-4">
              <button 
                onClick={handleBulkPrompt}
                className="px-6 py-4 bg-slate-700 text-white text-[11px] font-black rounded-xl hover:bg-slate-800 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>
                Tự động viết tất cả prompt
              </button>
              <button 
                onClick={downloadAllImages}
                className="px-6 py-4 bg-white text-slate-900 text-[11px] font-black rounded-xl hover:bg-slate-100 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                Ảnh (ZIP)
              </button>
              <button 
                onClick={downloadPrompts}
                className="px-6 py-4 bg-orange-50 text-orange-700 text-[11px] font-black rounded-xl hover:bg-orange-100 transition-all uppercase flex items-center gap-2 shadow-lg"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                Prompt (.TXT)
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg) => (
              <div key={seg.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                  {seg.image.url ? (
                    <img src={seg.image.url} className={`w-full h-full object-cover ${seg.image.loading ? 'blur-sm grayscale opacity-50' : ''}`} alt={`Step ${seg.id}`} />
                  ) : null}
                  {seg.image.loading && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/5 backdrop-blur-sm">
                      <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                      <span className="mt-4 text-[10px] font-black text-orange-600 uppercase animate-pulse">Đang dựng hình...</span>
                    </div>
                  )}
                  <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-full border border-white/10 shadow-lg">CẢNH #{seg.id}</div>
                </div>

                <div className="p-6 space-y-4 flex flex-col flex-1">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Nội dung thay đổi:</label>
                    <textarea 
                      value={seg.content}
                      onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))}
                      className="w-full h-28 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white transition-all leading-relaxed shadow-inner resize-none"
                    />
                  </div>

                  <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                    <button 
                      onClick={() => handleGenImage(seg.id)}
                      disabled={seg.image.loading}
                      className="py-4 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase tracking-tighter hover:bg-black transition-all flex items-center justify-center gap-1 shadow-md"
                    >
                      {seg.image.loading ? "Chờ..." : (seg.image.url ? "Tạo lại ảnh" : "Vẽ ảnh AI")}
                    </button>
                    <button 
                      onClick={() => handleGenPrompt(seg.id)}
                      disabled={seg.videoPrompt.loading || !seg.image.url}
                      className="py-4 bg-orange-50 text-orange-700 text-[10px] font-black rounded-xl uppercase tracking-tighter border border-orange-200 hover:bg-orange-200 transition-all flex items-center justify-center gap-1 disabled:opacity-30 shadow-sm"
                    >
                      {seg.videoPrompt.loading ? "..." : "Tạo Prompt"}
                    </button>
                  </div>
                </div>

                {seg.videoPrompt.visible && (
                  <div className="p-5 bg-slate-900 border-t border-slate-800 animate-slideUp">
                    <div className="flex justify-between items-center mb-3">
                      <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Video Prompt Tiếng Việt</span>
                      <button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[9px] font-black text-white hover:text-emerald-400 underline">COPY</button>
                    </div>
                    {seg.videoPrompt.loading ? (
                      <div className="h-10 flex items-center justify-center"><div className="w-5 h-5 border-2 border-emerald-500 border-t-white rounded-full animate-spin"></div></div>
                    ) : (
                      <textarea 
                        value={seg.videoPrompt.text}
                        onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, videoPrompt: { ...s.videoPrompt, text: e.target.value } } : s))}
                        className="w-full bg-transparent text-[10px] text-slate-300 italic leading-snug outline-none resize-none border-none p-0"
                        rows={4}
                      />
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default TimelapseModule;

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { scenes: 2, label: '2 cảnh - 16s' },
  { scenes: 3, label: '3 cảnh - 24s' },
  { scenes: 4, label: '4 cảnh - 32s' },
  { scenes: 5, label: '5 cảnh - 40s' },
  { scenes: 6, label: '6 cảnh - 48s' },
  { scenes: 7, label: '7 cảnh - 56s' },
  { scenes: 8, label: '8 cảnh - 64s' },
];

const TimelapseModule: React.FC = () => {
  const storageKey = "timelapse_project_v3_dual_ref";
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [finalFile, setFinalFile] = useState<File | null>(null);
  const [finalPreview, setFinalPreview] = useState<string | null>(null);
  const [idea, setIdea] = useState('');
  const [sceneCount, setSceneCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const segmentsRef = useRef<TimelapseSegment[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const finalInputRef = useRef<HTMLInputElement>(null);

  // Sync ref with state to always have latest data in async calls
  useEffect(() => {
    segmentsRef.current = segments;
  }, [segments]);

  // Restore from LocalStorage on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setIdea(parsed.idea || '');
        setSceneCount(parsed.sceneCount || 4);
        setBasePreview(parsed.basePreview || null);
        setFinalPreview(parsed.finalPreview || null);
        const restoredSegments = (parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: s.image.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }));
        setSegments(restoredSegments);
        segmentsRef.current = restoredSegments;
      }
    } catch (e) {
      console.error("Restore Timelapse state fail", e);
    }
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    try {
      const toSave = {
        idea,
        sceneCount,
        basePreview: basePreview?.startsWith('data:') ? basePreview : '',
        finalPreview: finalPreview?.startsWith('data:') ? finalPreview : '',
        segments: segments.map(s => ({
          ...s,
          image: { ...s.image, url: s.image.url?.startsWith('data:') ? s.image.url : '' },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }))
      };
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [idea, sceneCount, basePreview, finalPreview, segments]);

  // Handle Export/Import
  useEffect(() => {
    const handleExport = () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: { idea, sceneCount, baseImage: basePreview, finalImage: finalPreview },
        script: seg.content,
        outputImage: seg.image.url || '',
        videoPrompt: seg.videoPrompt.text || ''
      }));
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'Timelapse_Project' } 
      }));
    };
    const handleImport = async (e: any) => {
        const importedData = e.detail;
        if (!Array.isArray(importedData)) return;
        setIdea(importedData[0]?.inputs?.idea || '');
        setSegments(importedData.map((item: any, idx: number) => ({
            id: idx + 1,
            content: item.script || '',
            image: { url: item.outputImage || '', loading: false },
            videoPrompt: { text: item.videoPrompt || '', loading: false, visible: !!item.videoPrompt }
        })));
    };
    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [segments, idea, sceneCount, basePreview, finalPreview]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBaseFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setBasePreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFinalFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setFinalPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleStart = async () => {
    if (!basePreview || !idea.trim()) {
      alert("Vui lòng tải ảnh hiện trạng và nhập ý tưởng cải tạo.");
      return;
    }
    setIsProcessing(true);
    try {
      const descriptions = await service.generateTimelapseScript(idea, sceneCount);
      const newSegments: TimelapseSegment[] = descriptions.map((desc, i) => {
        const isFirst = i === 0;
        const isLast = i === sceneCount - 1;
        return {
          id: i + 1,
          content: desc,
          image: { 
            // Cảnh 1 gán ảnh bắt đầu, cảnh cuối gán ảnh kết thúc (nếu có)
            url: isFirst ? basePreview : (isLast && finalPreview ? finalPreview : ''), 
            loading: false,
            regenNote: ''
          },
          videoPrompt: { text: '', loading: false, visible: false }
        };
      });
      setSegments(newSegments);
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleGenImage = async (id: number) => {
    const idx = id - 1;
    const currentSegments = segmentsRef.current;
    const current = currentSegments[idx];
    const isLast = id === currentSegments.length;

    // Nếu là cảnh cuối và đã có ảnh kết thúc, sử dụng luôn ảnh đó không cần gọi AI
    if (isLast && finalPreview) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: finalPreview, loading: false } } : s));
      return finalPreview;
    }

    // Set loading state
    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));

    try {
      // 1. Ảnh gốc ban đầu
      let basePart = null;
      if (baseFile) {
        basePart = await service.fileToGenerativePart(baseFile);
      } else if (basePreview?.startsWith('data:')) {
        basePart = { mimeType: 'image/png', data: basePreview.split(',')[1] };
      }

      // 2. Ảnh ngay phía trước (Quan trọng nhất để giữ cấu trúc)
      let prevPart = null;
      const prevImage = currentSegments[idx - 1]?.image?.url;
      if (idx > 0 && prevImage) {
        prevPart = { 
          mimeType: 'image/png', 
          data: prevImage.split(',')[1] 
        };
      }

      // 3. Ảnh kết thúc mục tiêu (Để AI không bị lạc đường)
      let finalPart = null;
      if (finalFile) {
        finalPart = await service.fileToGenerativePart(finalFile);
      } else if (finalPreview?.startsWith('data:')) {
        finalPart = { mimeType: 'image/png', data: finalPreview.split(',')[1] };
      }

      const url = await service.generateTimelapseImage(
        current.content,
        basePart,
        prevPart,
        finalPart,
        id === 1,
        isLast
      );

      // Dự phòng nếu API không trả về ảnh cho cảnh 1 (thực tế code UI đã chặn)
      const finalUrl = url || (id === 1 ? basePreview : (isLast && finalPreview ? finalPreview : ''));

      setSegments(prev => {
          const next = prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: finalUrl, loading: false } } : s);
          segmentsRef.current = next; 
          return next;
      });

      return finalUrl;
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi AI' } } : s));
      throw e;
    }
  };

  const handleGenPrompt = async (id: number) => {
    const idx = id - 1;
    const current = segments[idx];
    if (!current.image.url) return;

    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateTimelapseVideoPrompt(current.content, current.image.url);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkPrompt = async () => {
    for (const seg of segments) {
        if (seg.image.url) {
            await handleGenPrompt(seg.id);
        }
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Vui lòng đợi thư viện tải xuống.");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        const base64 = s.image.url.split(',')[1];
        if (base64) {
          zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64, { base64: true });
          count++;
        }
      }
    });
    if (count === 0) return alert("Không có hình ảnh nào để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const downloadPrompts = () => {
    const text = segments
      .map(s => s.videoPrompt.text.replace(/\n/g, ' ').trim())
      .filter(t => t.length > 0)
      .join('\n');
    if (!text) return alert("Chưa có video prompt nào được tạo.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `timelapse_prompts_${Date.now()}.txt`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Input UI */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-6">
            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-widest px-1">1. Hình ảnh tham chiếu (Ảnh đầu & Ảnh cuối)</label>
              <div className="grid grid-cols-2 gap-4">
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {basePreview ? (
                    <img src={basePreview} className="w-full h-full object-cover" alt="Source" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Ảnh hiện trạng</span>
                    </div>
                    )}
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
                    {basePreview && <div className="absolute bottom-2 left-2 bg-black/60 text-white text-[8px] font-black px-2 py-1 rounded uppercase">Bắt đầu</div>}
                </div>

                <div 
                    onClick={() => finalInputRef.current?.click()}
                    className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group shadow-inner"
                >
                    {finalPreview ? (
                    <img src={finalPreview} className="w-full h-full object-cover" alt="Final Goal" />
                    ) : (
                    <div className="text-center opacity-30">
                        <svg className="w-10 h-10 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                        <span className="text-[10px] font-black uppercase tracking-widest">Kết quả cuối (Tùy chọn)</span>
                    </div>
                    )}
