export const analyzeFinalImage = async (imagePart: any): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Nhiệm vụ: Hãy đóng vai chuyên gia thiết kế nội thất và thi công, bóc tách chi tiết hình ảnh này.
