      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (error) {
    console.error("Script generation error", error);
    return Array(sceneCount).fill("Đang thi công...");
  }
};

/**
 * Task 2: Tạo hình ảnh - CHIẾN THUẬT INFUSION (Truyền dẫn vật liệu)
 */
export const generateTimelapseImage = async (
  sceneDescription: string,
  baseImagePart: any,
  previousImagePart: any | null,
  finalGoalPart: any | null,
  isFirst: boolean,
  isLast: boolean
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";

  if (isFirst) return ""; 

  // Prompt kỹ thuật cao để ép AI không được sáng tạo bừa bãi
  const prompt = `
    TASK: Architectural Infusion (Progressive Construction Frame).
    STYLE: Photorealistic RAW PHOTO, 8k, architectural cinematography.
    RATIO: 9:16 portrait.

    REFERENCE ROLES:
    - [SOURCE_FRAME]: Provided as the starting point (layout, camera angle, fixed structures).
    - [MATERIAL_TARGET]: Provided as the ONLY source for textures, colors, and furniture design.

    INSTRUCTIONS:
    1. !!! 1:1 TEXTURE CLONE (MANDATORY) !!!: 
       Any new surface being added (like the FLOOR or WALLS) in this step MUST be a pixel-perfect match to the [MATERIAL_TARGET]. 
       - If it's wood flooring: use the EXACT same plank width, wood grain pattern, and warm oak color from the goal image.
       - DO NOT use generic or different wood. It MUST be the floor from the goal image.

    2. !!! PROGRESSIVE COMPLETION !!!: 
       Current Phase: "${sceneDescription}".
       Modify the [SOURCE_FRAME] by adding elements from [MATERIAL_TARGET] according to the phase. 
       The camera position and lighting MUST remain identical to [SOURCE_FRAME].

    3. !!! ASSET CONSISTENCY !!!:
       Furniture and decor added MUST be identical models to those seen in [MATERIAL_TARGET].

    4. !!! CLEANLINESS !!!:
       NO TEXT, NO LOGOS, NO WATERMARKS.
  `;

  const contents: any[] = [{ text: prompt }];

  // Hình ảnh 1: Khung xương (Ảnh trước đó)
  if (previousImagePart) {
      contents.push({ inlineData: previousImagePart }); 
  } else {
      contents.push({ inlineData: baseImagePart });
  }

  // Hình ảnh 2: Nguồn vật liệu (Ảnh kết thúc)
  if (finalGoalPart) {
    contents.push({ inlineData: finalGoalPart });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("Fail to generate image");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) {
    console.error("Image generation error", error);
    throw error;
  }
};

